-- 최종 1000개 데이터 확인
SELECT 
    '🎉🎉🎉 MoneyShift 완벽한 1000개 거래 테스트 데이터 완성! 🎉🎉🎉' as final_message,
    COUNT(*) as total_records,
    COUNT(*) FILTER (WHERE source_type = 'BANK') as bank_transactions,
    COUNT(*) FILTER (WHERE source_type = 'CARD') as card_transactions,
    COUNT(DISTINCT test_category) as unique_categories,
    COUNT(DISTINCT business_type) as unique_business_types,
    COUNT(DISTINCT region) as unique_regions,
    MIN(amount) as min_amount,
    MAX(amount) as max_amount,
    ROUND(AVG(amount)::numeric, 2) as avg_amount,
    COUNT(*) FILTER (WHERE difficulty_level = 1) as easy_cases,
    COUNT(*) FILTER (WHERE difficulty_level = 2) as medium_cases,
    COUNT(*) FILTER (WHERE difficulty_level = 3) as hard_cases,
    COUNT(*) FILTER (WHERE difficulty_level = 4) as very_hard_cases,
    COUNT(*) FILTER (WHERE amount > 0) as positive_amounts,
    COUNT(*) FILTER (WHERE amount < 0) as negative_amounts
FROM transaction_test_data;